class Solution:
    def average(self, salary):
        ordered = sorted(salary)
        middle = ordered[1:-1]
        return sum(middle) / len(middle)

solutions.python:
class Solution:
    def average(self, salary):
        lo = min(salary)
        hi = max(salary)
        total = sum(salary) - lo - hi
        return total / (len(salary) - 2)

