var average = function(salary) {
    let lo = Infinity, hi = -Infinity, total = 0;
    for (const s of salary) {
        total += s;
        if (s < lo) lo = s;
        if (s > hi) hi = s;
    }
    return (total - lo - hi) / (salary.length - 2);
};
